parameters.inputSchema:
{
	"type": "object",
	"properties": {
		"complexity": {
			"type": "string",
			"enum": ["simple", "complex"],
			"description": "Task complexity level"
		},
		"confidence": {
			"type": "number",
			"minimum": 0,
			"maximum": 1,
			"description": "Confidence score for the classification"
		},
		"reasoning": {
			"type": "string",
			"description": "Brief explanation of the classification decision"
		}
	},
	"required": ["complexity", "confidence", "reasoning"]
}

parameters.text:
=A task was classified with low confidence and requires human review.

User Request: {{ $('Workflow Configuration').first().json.userRequest }}

Classification: {{ $json.complexity }}
Confidence Score: {{ $json.confidence }}
Reasoning: {{ $json.reasoning }}

Threshold: {{ $('Workflow Configuration').first().json.confidenceThreshold }}

Please review this task manually.
